import { create } from 'zustand';
import { api } from '@/services/api';
import type { Conversation, Message, ModelParams } from '@/types';

interface ConversationState {
  conversations: Conversation[];
  activeId: string | null;
  active: Conversation | null;
  messages: Message[];
  streaming: boolean;
  streamingContent: string;
  error: string | null;
  loading: boolean;

  loadList: () => Promise<void>;
  selectConversation: (id: string) => Promise<void>;
  create: () => Promise<string>;
  update: (id: string, data: Partial<Conversation>) => Promise<void>;
  remove: (id: string) => Promise<void>;
  sendMessage: (content: string, opts?: SendOpts) => Promise<void>;
  cancelStream: () => void;
  editMessage: (msgId: string, content: string) => Promise<void>;
  deleteMessage: (msgId: string) => Promise<void>;
  clearError: () => void;
}

interface SendOpts {
  providerId: string;
  modelId: string;
  params?: ModelParams;
  tools?: unknown[];
}

let abortController: AbortController | null = null;

export const useConversationStore = create<ConversationState>((set, get) => ({
  conversations: [],
  activeId: null,
  active: null,
  messages: [],
  streaming: false,
  streamingContent: '',
  error: null,
  loading: false,

  loadList: async () => {
    set({ loading: true });
    try {
      const data = await api.getConversations({ archived: false });
      set({ conversations: data, loading: false });
    } catch {
      set({ loading: false });
    }
  },

  selectConversation: async (id: string) => {
    set({ activeId: id, streamingContent: '', error: null });
    try {
      const data = await api.getConversation(id);
      const { messages, ...conv } = data;
      set({ active: conv, messages: messages || [] });
    } catch {
      set({ error: 'Failed to load conversation' });
    }
  },

  create: async () => {
    const conv = await api.createConversation({});
    set(state => ({
      conversations: [conv, ...state.conversations],
      activeId: conv.id,
      active: conv,
      messages: [],
      error: null,
    }));
    return conv.id;
  },

  update: async (id, data) => {
    await api.updateConversation(id, data as any);
    set(state => ({
      conversations: state.conversations.map(c => c.id === id ? { ...c, ...data } : c),
      active: state.active?.id === id ? { ...state.active, ...data } : state.active,
    }));
  },

  remove: async (id) => {
    await api.deleteConversation(id);
    set(state => {
      const next = state.conversations.filter(c => c.id !== id);
      if (state.activeId === id) {
        return { conversations: next, activeId: null, active: null, messages: [] };
      }
      return { conversations: next };
    });
  },

  sendMessage: async (content, opts) => {
    const { activeId: convId, active } = get();
    const providerId = opts?.providerId;
    const modelId = opts?.modelId;

    if (!providerId || !modelId) {
      set({ error: 'No provider or model selected' });
      return;
    }

    // Optimistic user message
    const userMsg: Message = {
      id: `temp-${Date.now()}`,
      conversation_id: convId || '',
      role: 'user',
      content,
      created_at: new Date().toISOString(),
    };

    set(state => ({
      messages: [...state.messages, userMsg],
      streaming: true,
      streamingContent: '',
      error: null,
    }));

    abortController = new AbortController();
    let fullContent = '';

    try {
      await api.chatCompletions(
        {
          provider_id: providerId,
          model_id: modelId,
          conversation_id: convId,
          messages: [{ role: 'user', content }],
          params: opts?.params || active?.params || {},
          tools: opts?.tools,
        },
        (chunkStr) => {
          try {
            const chunk = JSON.parse(chunkStr);
            const delta = chunk.choices?.[0]?.delta?.content;
            if (delta) {
              fullContent += delta;
              set({ streamingContent: fullContent });
            }
          } catch {}
        },
        abortController.signal
      );

      // Streaming complete — add assistant message
      const assistantMsg: Message = {
        id: `assistant-${Date.now()}`,
        conversation_id: convId || '',
        role: 'assistant',
        content: fullContent,
        created_at: new Date().toISOString(),
      };

      set(state => ({
        messages: [...state.messages, assistantMsg],
        streaming: false,
        streamingContent: '',
      }));

      // Refresh conversation list (title auto-generated)
      get().loadList();
      // Reload conversation to get real message IDs
      if (convId) {
        get().selectConversation(convId);
      }
    } catch (err: any) {
      if (err?.name === 'AbortError') {
        // User cancelled — save partial
        if (fullContent) {
          const partialMsg: Message = {
            id: `partial-${Date.now()}`,
            conversation_id: convId || '',
            role: 'assistant',
            content: fullContent + '\n\n*(cancelled)*',
            created_at: new Date().toISOString(),
          };
          set(state => ({ messages: [...state.messages, partialMsg] }));
        }
      } else {
        set({ error: err?.error?.message || err?.message || 'Request failed' });
      }
      set({ streaming: false, streamingContent: '' });
    } finally {
      abortController = null;
    }
  },

  cancelStream: () => {
    abortController?.abort();
  },

  editMessage: async (msgId, content) => {
    set(state => ({
      messages: state.messages.map(m => m.id === msgId ? { ...m, content } : m),
    }));
    try {
      await api.updateMessage(msgId, { content });
    } catch {
      // reload on error
    }
  },

  deleteMessage: async (msgId) => {
    set(state => ({
      messages: state.messages.filter(m => m.id !== msgId),
    }));
    try {
      await api.deleteMessage(msgId);
    } catch {
      // reload on error
    }
  },

  clearError: () => set({ error: null }),
}));
